+/// WHERE clause node
+pub const WhereClause = struct {
+    op: WhereOp,
+    column: ?[]const u8,
+    // For comparison ops
+    value_int: ?i64,
+    value_float: ?f64,
+    value_string: ?[]const u8,
+    // For BETWEEN
+    low_int: ?i64,
+    high_int: ?i64,
+    low_float: ?f64,
+    high_float: ?f64,
