+/// SQL input buffer
+var sql_input: [4096]u8 = undefined;
+var sql_input_len: usize = 0;
+
+/// Get SQL input buffer for JS to write to
+pub export fn getSqlInputBuffer() [*]u8 {
+    return &sql_input;
+}
